#include<stdio.h>
#include<string.h>
int adj[1001][5001],deg[1001],indeg[1001],q[1001],res[1001];
int main(){int n,m;scanf("%d %d",&n,&m);for(int i=0;i<m;i++){int u,v;scanf("%d %d",&u,&v);adj[u][deg[u]++]=v;indeg[v]++;}int front=0,back=0,k=0;for(int i=0;i<n;i++)if(!indeg[i])q[back++]=i;while(front<back){int u=q[front++];res[k++]=u;for(int j=0;j<deg[u];j++){int v=adj[u][j];if(--indeg[v]==0)q[back++]=v;}}for(int i=0;i<n;i++)printf("%d%c",res[i],i<n-1?' ':'\n');}
